previewCss:
.darma-loader-uiverse-corner-path-square {
  width: 50px;
  aspect-ratio: 1;
  display: grid;
}
.darma-loader-uiverse-corner-path-square:before,
.darma-loader-uiverse-corner-path-square:after {
  content: "";
  grid-area: 1/1;
  margin: 0 0 15px 15px;
  --c: #0000 calc(100% / 3), #046d8b 0 calc(2 * 100% / 3), #0000 0;
  --c1: linear-gradient(90deg, var(--c));
  --c2: linear-gradient(0deg, var(--c));
  background: var(--c1), var(--c2), var(--c1), var(--c2);
  background-size:
    300% 4px,
    4px 300%;
  background-repeat: no-repeat;
  animation: darma-loader-uiverse-corner-path-square-l12 1s infinite linear;
}
.darma-loader-uiverse-corner-path-square:after {
  margin: 15px 15px 0 0;
  transform: scale(-1, -1);
}
@keyframes darma-loader-uiverse-corner-path-square-l12 {
  0% {
    background-position:
      50% 0,
      100% 100%,
      0 100%,
      0 0;
  }
  25% {
    background-position:
      0 0,
      100% 50%,
      0 100%,
      0 0;
  }
  50% {
    background-position:
      0 0,
      100% 0,
      50% 100%,
      0 0;
  }
  75% {
    background-position:
      0 0,
      100% 0,
      100% 100%,
      0 50%;
  }
  75.01% {
    background-position:
      100% 0,
      100% 0,
      100% 100%,
      0 50%;
  }
  100% {
    background-position:
      50% 0,
      100% 0,
      100% 100%,
      0 100%;
  }
}

